const TAG = 'BatchDeleteGroup ';
const DELETE_GROUP_EVENT = 'DELETE_GROUP_EVENT';
const GROUP_DELETE_DIALOG_EVENT = 'GROUP_DELETE_DIALOG_EVENT';
