import {
  getTextWidth,
  getDefaultFocusIdx,
  getToolBarList,
  initColorBlendData,
  ItemState,
  getLeftFocusIdx,
  getRightFocusIdx,
  ToolBarOptions,
  ToolBarOption
} from "../../utils/ToolbarDialogUtils";
import Curves from '@ohos.curves';
import { KeyCode } from '@ohos.multimodalInput.keyCode';

const ITEM_WIDTH: number = 96;
const ITEM_HEIGHT: number = 96;
const TOOL_HEIGHT: number = 97;
const TOOL_BAR_PADDING: number = 24;
const TOOL_BAR_DX: number = 0;
const TOOL_BAR_DY: number = -64;
const ITEM_PADDING_TOP: number = 12;
const IMAGE_BACKBOARD: number = 40;
const IMAGE_SIZE: number = 24;
const TEXT_MARGIN_DEFAULT: number = 8;
const TEXT_MARGIN_CHANGE: number = 4;
const ITEM_PRESS_COLOR_BLENDS: Resource = $r("app.color.toolbarDialog_item_press_colorBlends");
const ITEM_HOVER_COLOR_BLENDS: Resource = $r("app.color.toolbarDialog_item_hover_colorBlends");
const ID_SUFFIX: string = getContext().resourceManager.getStringByNameSync('toolbardialog_id_suffix');

@CustomDialog
export struct ToolBarDialog {
  @Prop toolbarList: ToolBarOptions;
  @Link @Watch('refreshIsOpen') isOpen: boolean;
  @State toolBarOpen: boolean = true;
  @State appearTime: number = 100;
  toolBarDialogController: CustomDialogController = new CustomDialogController({
    builder: FloatToolBarDialogContent({
      toolBarList: this.toolbarList,
      toolBarOpen: this.toolBarOpen
    }),
    customStyle: true,
    autoCancel: true,
    alignment: DialogAlignment.Bottom,
    offset: { dx: TOOL_BAR_DX, dy: TOOL_BAR_DY },
    cancel: () => {
      this.isOpen = false;
    }
  })

  build() {
  }

  aboutToAppear(): void {
    let itemNumber = this.toolbarList?.length;
    if (this.isOpen && itemNumber > 0) {
      setTimeout(() => {
        this.toolBarOpen = true;
        this.toolBarDialogController?.open();
      }, this.appearTime)
    }
  }

  refreshIsOpen() {
    let itemNumber = this.toolbarList?.length;
    if (this.isOpen && itemNumber > 0) {
      this.toolBarOpen = true;
      this.toolBarDialogController?.open();
    } else {
      this.toolBarOpen = false;
      this.toolBarDialogController?.close();
    }
  }
}

@CustomDialog
struct FloatToolBarDialogContent {
  @State toolBarList: ToolBarOptions = [];
  @State colorBlends: Resource | Color | string = $r("app.string.toolbarDialog_colorBlends");
  @State curFocusIdx: number | null = null;
  @State curHoverIdx: number | null = null;
  @State defaultFocusIdx: number | null = null;
  @State isDefaultLeftOrRight: boolean = false;
  @State content: Resource | string = $r("app.string.toolbarDialog_content");
  @State itemWidth: number = ITEM_WIDTH;
  @State leftFocusIdx: number | null = null;
  @State rightFocusIdx: number | null = null;
  @Link toolBarOpen: boolean;
  controller: CustomDialogController;
  toolBarColorBlends: Resource | Color | string[] = [];
  tooBarController: TabsController = new TabsController();

  @Builder
  tabBarContent(item: ToolBarOption, index: number) {
    Button({ type: ButtonType.Circle, stateEffect: false }) {
      Image(this.getImage(index, item))
        .focusable(true)
        .fillColor(this.curFocusIdx === index && item?.state !== ItemState.DISABLE ?
        $r('sys.color.ohos_id_color_focused_content_primary') : $r('sys.color.ohos_id_color_toolbar_icon'))
        .width(IMAGE_SIZE)
        .height(IMAGE_SIZE)
    }
    .focusable(true)
    .width(IMAGE_BACKBOARD)
    .height(IMAGE_BACKBOARD)
    .shadow({ radius: 0, color: 0 })
    .hoverEffect(HoverEffect.None)
    .backgroundColor(this.curFocusIdx === index && item?.state !== ItemState.DISABLE ?
    $r('app.color.toolbarDialog_focus_bg_color') : Color.Transparent)

    Text(item?.content)
      .fontSize($r('sys.float.ohos_id_text_size_sub_title3'))
      .fontColor($r('sys.color.ohos_id_color_toolbar_text'))
      .margin({
        right: this.itemWidth > ITEM_WIDTH ? TEXT_MARGIN_CHANGE : TEXT_MARGIN_DEFAULT,
        left: this.itemWidth > ITEM_WIDTH ? TEXT_MARGIN_CHANGE : TEXT_MARGIN_DEFAULT,
        top: TEXT_MARGIN_CHANGE
      })
      .fontWeight(FontWeight.Medium)
      .textOverflow({ overflow: TextOverflow.MARQUEE })
      .marqueeOptions({
        start: (index === this.curFocusIdx || this.curHoverIdx) && item?.state !== ItemState.DISABLE,
        fadeout: true,
        marqueeStartPolicy: MarqueeStartPolicy.DEFAULT
      })
  }

  @Builder
  tabBar(item: ToolBarOption, index: number) {
    Column() {
      this.tabBarContent(item, index);
    }
    .colorBlend(this.colorBlends)
    .onClick(() => {
      if (item?.action) {
        if (!(item?.state === ItemState.DISABLE)) {
          item?.action();
        }
      }
    })
    .height('100%')
    .width(this.itemWidth)
    .enabled(!(this.toolBarList[index]?.state === ItemState.DISABLE))
    .opacity((this.toolBarList[index]?.state === ItemState.DISABLE) ? 0.4 : 1)
    .borderRadius($r('sys.float.ohos_id_corner_radius_default_m'))
    .padding({ top: ITEM_PADDING_TOP })
    .id(String(index) + ID_SUFFIX)
    .onHover((isHover: boolean) => {
      if (isHover) {
        this.toolBarColorBlends[index] =
          (this.toolBarList[index]?.state === ItemState.DISABLE) ? '' : ITEM_HOVER_COLOR_BLENDS;
        this.curHoverIdx = index;
      } else {
        this.toolBarColorBlends[index] = Color.Transparent;
        this.curHoverIdx = null;
      }
      this.colorBlends = this.toolBarColorBlends[index];
    })
    .onFocus(() => {
      this.curFocusIdx = index;
    })
    .onKeyEvent((event: KeyEvent) => {
      this.isOpenAndCaptureFocus(event, index);
    })
    .stateStyles({
      pressed: {
        .colorBlend((this.toolBarList[index]?.state === ItemState.DISABLE) ? '' : ITEM_PRESS_COLOR_BLENDS)
      },
      normal: {
        .colorBlend(this.toolBarColorBlends[index])
      }
    })
  }

  build() {
    Column() {
      Row() {
        ForEach(this.toolBarList, (item: ToolBarOption, index: number) => {
          this.tabBar(item, index);
        })
      }
      .height(ITEM_HEIGHT)
    }
    .height(TOOL_HEIGHT)
    .width(this.itemWidth * this.toolBarList?.length + TOOL_BAR_PADDING * 2)
    .border({ width: 0.5, color: ITEM_PRESS_COLOR_BLENDS, radius: $r('sys.float.ohos_id_corner_radius_default_m') })
    .shadow(ShadowStyle.OUTER_DEFAULT_LG)
    .padding({ left: TOOL_BAR_PADDING, right: TOOL_BAR_PADDING })
    .backgroundColor($r('sys.color.ohos_id_color_toolbar_sub_bg'))
    .visibility(this.toolBarOpen ? Visibility.Visible : Visibility.Hidden)
    .transition(TransitionEffect.OPACITY.animation({ curve: Curves.interpolatingSpring(0, 1, 228, 26) })
      .combine(TransitionEffect.translate({ y: 160 }))
      .combine(TransitionEffect.scale({ x: 0, y: 0 })))
  }

  aboutToAppear() {
    let itemNumber = this.toolBarList?.length;
    this.toolBarList = getToolBarList(this.toolBarList, itemNumber);
    let realityNumber = this.toolBarList?.length;
    this.itemWidth = getTextWidth(this.toolBarList, realityNumber);
    this.defaultFocusIdx = getDefaultFocusIdx(this.toolBarList, realityNumber);
    this.toolBarColorBlends = initColorBlendData(this.toolBarColorBlends, realityNumber);
    this.leftFocusIdx = getLeftFocusIdx(this.toolBarList, realityNumber);
    this.rightFocusIdx = getRightFocusIdx(this.toolBarList, realityNumber);
  }

  isOpenAndCaptureFocus(event: KeyEvent, index: number) {
    if (event?.type === KeyType.Down) {
      switch (event?.keyCode) {
        case KeyCode.KEYCODE_DPAD_RIGHT:
          if (index === this.rightFocusIdx) {
            focusControl.requestFocus(String(this.leftFocusIdx) + ID_SUFFIX);
          }
          break;
        case KeyCode.KEYCODE_DPAD_LEFT:
          if (index === this.leftFocusIdx) {
            focusControl.requestFocus(String(this.rightFocusIdx) + ID_SUFFIX);
          }
          break;
        default:
          break;
      }
    }
  }

  getImage(index: number, item: ToolBarOption) {
    if (this.curFocusIdx == index && item?.focusIcon) {
      return item?.focusIcon;
    }
    return item?.icon;
  }
}

