  destinationBackPress(): boolean {

    if (this.multiSelectFlag === Visibility.Visible) {
      this.cancelSelectState();
      return true;
    }
    if (AppStorage.get('curBp') as string !== common.STR.DEVICE_MOBILE_PHONE) {
      DeviceUtil.foldMenuPageBack(this.pageInfos)
    } else {
      this.pageInfos?.pop();
