      .onClick(() => {
        this.show = false;
        this.showMenu = false;
        this.mFavoriteCtrl.isSelectStatus = true;
        this.mFavoriteCtrl.mmsIndex = this.itemIndex;
        this.item.isCbChecked = true;
        this.multiSelectFlag = Visibility.Visible
        this.menuMultSelect(this.itemIndex);
      })
