  @Builder
  saveMenuButton() {
    MenuItem() {
      SaveButton({ text: SaveDescription.SAVE, buttonType: ButtonType.Normal })
        .backgroundColor(Color.Transparent)
        .fontColor($r('sys.color.font_primary'))
        .fontSize($r('sys.float.Body_L'))
